impl Solution { pub fn smallest_string(black_s: String) -> String { let mut black_b = black_s.into_bytes(); let mut black_i = 0; while black_i < black_b.len() && black_b[black_i] == b'a' { black_i += 1; } if black_i == black_b.len() { *black_b.last_mut().unwrap() = b'z'; } else { while black_i < black_b.len() && black_b[black_i] != b'a' { black_b[black_i] -= 1; black_i += 1; } } String::from_utf8(black_b).unwrap() } }